sqlServer.code:
-- Create Login (Server Level)
CREATE LOGIN [john_doe] WITH PASSWORD = 'SecurePassword123!';

-- Create User (Database Level)
USE AdventureWorks2019;
CREATE USER [john_doe] FOR LOGIN [john_doe];

-- Create Database Role
CREATE ROLE db_reports;

-- Add User to Role
ALTER ROLE db_reports ADD MEMBER [john_doe];

postgres.code:
-- Create Role (User and Role are the same concept)
CREATE ROLE john_doe WITH LOGIN PASSWORD 'SecurePassword123!';

-- Create Group Role
CREATE ROLE db_reports;

-- Grant membership
GRANT db_reports TO john_doe;

-- Alternative: Create user directly
CREATE USER jane_smith WITH PASSWORD 'AnotherSecurePassword!';

sqlServer.code:
-- Grant permissions on schema objects
GRANT SELECT, INSERT ON dbo.Customers TO [john_doe];
GRANT EXECUTE ON dbo.GetCustomerById TO db_reports;

-- Schema-level permissions
GRANT SELECT ON SCHEMA::Sales TO db_reports;

-- Database-level permissions
GRANT CREATE TABLE TO [john_doe];

-- View permissions
SELECT
    p.permission_name,
    p.state_desc,
    pr.name AS principal_name,
    o.name AS object_name
FROM sys.database_permissions p
JOIN sys.objects o ON p.major_id = o.object_id
JOIN sys.database_principals pr ON p.grantee_principal_id = pr.principal_id;

postgres.code:
-- Grant table privileges
GRANT SELECT, INSERT ON customers TO john_doe;
GRANT EXECUTE ON FUNCTION get_customer_by_id(int) TO db_reports;

-- Schema-level privileges
GRANT USAGE ON SCHEMA sales TO db_reports;
GRANT SELECT ON ALL TABLES IN SCHEMA sales TO db_reports;

-- Database-level privileges
GRANT CREATE ON DATABASE adventureworks TO john_doe;

-- View privileges
SELECT
    grantee,
    table_schema,
    table_name,
    privilege_type
FROM information_schema.table_privileges
WHERE grantee = 'john_doe';
